import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Divider } from '@mui/material';
import { Info } from '@mui/icons-material';
import response from './response.json';

interface CurrentShow {
  title: string;
  nextEpisode: string;
  episodesLeft: number;
  timeToFinish: string;
}

interface WatchlistItem {
  title: string;
  episodesLeft: number;
  timeToFinish: string;
}

interface WatchlistData {
  currentShow: CurrentShow;
  watchlist: WatchlistItem[];
}

export default function Widget() {
  const watchlistData = response.data as WatchlistData;
  const { currentShow, watchlist } = watchlistData;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 320,
        maxWidth: 450,
        bgcolor: response.meta.theme === 'dark' ? '#1C1C1E' : '#FFFFFF',
        color: '#FFFFFF',
        p: 2,
      }}
      elevation={2}
    >
      <CardContent>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: response.meta.primaryColor, mb: 1 }}>
              {currentShow.title}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
              Next Episode: {currentShow.nextEpisode}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Episodes Left: {currentShow.episodesLeft}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Time to Finish: {currentShow.timeToFinish}
            </Typography>
          </Box>

          <Divider sx={{ bgcolor: response.meta.accentColor }} />

          <Box>
            <Typography variant="body2" fontWeight={600} sx={{ mb: 1 }}>
              Watchlist
            </Typography>
            <Grid container spacing={1}>
              {watchlist.map((item, index) => (
                <Grid item xs={6} key={index}>
                  <Typography variant="body2" color="text.secondary" sx={{ fontWeight: 500 }}>
                    {item.title}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    {item.episodesLeft} episodes left
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    {item.timeToFinish}
                  </Typography>
                </Grid>
              ))}
            </Grid>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
